import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.DmWB24NN.js";const g=JSON.parse('{"title":"CHAPTER 5: ALIGNMENT","description":"","frontmatter":{},"headers":[],"relativePath":"Book I - Core Rules/B01 - Chapter 05_ Alignment.md","filePath":"Book I - Core Rules/B01 - Chapter 05_ Alignment.md"}'),i={name:"Book I - Core Rules/B01 - Chapter 05_ Alignment.md"};function r(s,e,l,h,d,c){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="chapter-5-alignment" tabindex="-1"><strong>CHAPTER 5: ALIGNMENT</strong> <a class="header-anchor" href="#chapter-5-alignment" aria-label="Permalink to &quot;**CHAPTER 5: ALIGNMENT**&quot;">​</a></h1><p>Alignment is a shorthand for a character&#39;s consistent orientation toward two questions: how much do they value order over freedom, and how much do they weigh others&#39; interests against their own? It is not a biography, and it is not a verdict. It describes a tendency — the pattern of choices a character makes when the rules are unclear, the stakes are real, and no one is watching.</p><p>Nine alignments exist, positioned along two axes. The first axis runs from Lawful to Chaotic. The second runs from Good to Evil. True Neutral sits at the intersection of both.</p><hr><h2 id="the-two-axes" tabindex="-1"><strong>The Two Axes</strong> <a class="header-anchor" href="#the-two-axes" aria-label="Permalink to &quot;**The Two Axes**&quot;">​</a></h2><p><strong>Law and Chaos</strong> — how a character relates to structure, hierarchy, and social obligation.</p><p>A Lawful character believes order is worth preserving. They operate within systems — codes, institutions, traditions, chains of command — and expect others to do the same. Their word means something specific, and they hold others to the same standard. This is not the same as obedience. A Lawful character may break a law they consider unjust. What they will not do is break a commitment they made willingly, undermine an institution they voluntarily joined, or treat agreements as provisional.</p><p>A Chaotic character believes individual judgment outweighs external authority. They resist being bound by codes they did not choose and institutions whose legitimacy they do not recognize. This is not the same as disorder. A Chaotic character can be reliable, principled, and loyal. What they resist is the claim that a rule, title, or tradition should override their assessment of what the situation actually requires.</p><p>A Neutral character on this axis is not caught between two poles. They make pragmatic judgments about when structure serves a purpose and when it does not. They do not carry a general position about law and freedom. They carry a case-by-case evaluation.</p><p><strong>Good and Evil</strong> — how a character weighs other people&#39;s interests against their own.</p><p>A Good character extends genuine weight to the well-being of others. This does not require self-sacrifice in every situation. It requires that others&#39; suffering registers as something worth acting on — that the cost to someone else matters in the calculation, not merely as a secondary consideration.</p><p>An Evil character prioritizes their own interests at others&#39; expense, either because they do not extend moral consideration to others or because they do and override it anyway. This is not cruelty for its own sake. Most Evil characters have coherent goals. The defining quality is that others are instruments or obstacles, not ends.</p><p>A Neutral character on this axis does not occupy a midpoint between caring about people and not caring. They operate according to local loyalties — their group, their immediate community, their contracted obligations — and do not extend those obligations broadly. The stranger&#39;s suffering is not their problem. Their companion&#39;s is.</p><hr><h2 id="the-nine-alignments" tabindex="-1"><strong>The Nine Alignments</strong> <a class="header-anchor" href="#the-nine-alignments" aria-label="Permalink to &quot;**The Nine Alignments**&quot;">​</a></h2><p><strong>Lawful Good.</strong> Operates within structures and extends genuine concern to others within and beyond those structures. Believes order and decency reinforce each other. When they conflict, decency takes precedence — a Lawful Good character breaks an unjust law rather than enforce it, but they do so openly and accept the consequences.</p><p><strong>Neutral Good.</strong> Wants good outcomes and will work through whatever structures or outside them to achieve them. Has no general position on law versus freedom. Makes decisions based on what actually helps.</p><p><strong>Chaotic Good.</strong> Extends genuine concern to others but distrusts centralized authority as a vehicle for achieving it. Acts on personal judgment. Believes institutions are more often the problem than the solution. May be unreliable allies to organizations while being fiercely loyal to individuals.</p><p><strong>Lawful Neutral.</strong> Committed to order, hierarchy, and codes without a corresponding commitment to others&#39; well-being beyond their defined obligations. The contract matters. The party outside the contract does not. Organizations run well. People outside the organization are not their concern.</p><p><strong>True Neutral.</strong> Operates without a consistent position on order versus freedom or on others&#39; interests. Makes decisions based on immediate circumstances, balance, or a specific set of local loyalties that do not generalize. Some True Neutral characters are balancers — they resist any faction becoming dominant. Most are simply people without strong ideological commitments.</p><p><strong>Chaotic Neutral.</strong> Prioritizes personal freedom above order and makes decisions primarily based on individual interest and judgment. Not malicious, but not reliably considerate of others. Self-directed in a way that can look like both Chaotic Good and Chaotic Evil depending on the situation, without being either consistently.</p><p><strong>Lawful Evil.</strong> Pursues their own interests or their institution&#39;s interests within the constraints of a code or structure. The code is a tool — it provides cover, creates predictability, and allows coordination with others toward shared ends. Breaks rules when they can do so safely and invisibly. Does not break rules that would cost them their position.</p><p><strong>Neutral Evil.</strong> Pursues self-interest without particular preference for order or freedom, using whichever is more useful in the moment. Has no ideological commitments. Can appear cooperative, even friendly, as long as cooperation serves their ends.</p><p><strong>Chaotic Evil.</strong> Pursues self-interest with contempt for constraint. Does not defer to codes, institutions, or others&#39; interests. May be impulsive or calculated — the defining quality is the absence of any limiting principle that would override self-interest or pleasure.</p><hr><h2 id="alignment-and-classes" tabindex="-1"><strong>Alignment and Classes</strong> <a class="header-anchor" href="#alignment-and-classes" aria-label="Permalink to &quot;**Alignment and Classes**&quot;">​</a></h2><p>Most characters have no mechanical relationship with their alignment. It describes their behavior. It does not generate consequences unless they abandon it entirely or belong to a class that has alignment requirements.</p><h3 id="classes-with-alignment-requirements" tabindex="-1"><strong>Classes with Alignment Requirements</strong> <a class="header-anchor" href="#classes-with-alignment-requirements" aria-label="Permalink to &quot;**Classes with Alignment Requirements**&quot;">​</a></h3><p><strong>Paladin.</strong> Must be Lawful. The specific alignment within the Lawful axis — Lawful Good, Lawful Neutral, or Lawful Evil — is determined by their deity. Paladins of the Three Sisters are Lawful Good. Paladins of Tar&#39;amaan are Lawful Neutral, trending Lawful Evil depending on the specific agent. A Paladin who shifts to any non-Lawful alignment loses all class abilities immediately and cannot recover them without divine atonement.</p><p><strong>Cleric.</strong> Must be within one alignment step of their deity. A deity of Lawful Good does not invest power in a Chaotic Evil cleric. The specific requirements are defined by each faith and detailed in Book II. A Cleric who moves outside their deity&#39;s permitted range loses spellcasting until they return or atone.</p><p><strong>Druid.</strong> Must be Neutral on at least one axis — either Lawful/Chaotic neutral or Good/Evil neutral. True Neutral is most common, but Neutral Good, Neutral Evil, Lawful Neutral, and Chaotic Neutral are all permitted. A Druid who abandons all Neutral positioning loses the Hyerophancy&#39;s sanction along with their spellcasting. The Hyerophancy considers this a matter of theological fitness, not personal discipline.</p><p><strong>Champion.</strong> No alignment requirement. The Champion&#39;s Code operates independently of alignment. A Chaotic Evil Champion following a code of personal honor and a Lawful Good Champion following an institutional oath both function identically by the rules — what changes is the content of their Code and the social consequences of following it.</p><hr><h2 id="tracking-alignment" tabindex="-1"><strong>Tracking Alignment</strong> <a class="header-anchor" href="#tracking-alignment" aria-label="Permalink to &quot;**Tracking Alignment**&quot;">​</a></h2><p>Alignment is not a number — no score that ticks up or down — but the pattern of a character&#39;s choices over time, and the GM observes that pattern.</p><p>A character whose consistent behavior has drifted significantly from their stated alignment should be told — privately if possible, before consequences attach. The GM is not obligated to wait until a violation becomes irrevocable. The conversation should happen at the point where the drift is clear, while the player still has the option to reorient the character or consciously shift to a new alignment.</p><h3 id="voluntary-change" tabindex="-1"><strong>Voluntary Change</strong> <a class="header-anchor" href="#voluntary-change" aria-label="Permalink to &quot;**Voluntary Change**&quot;">​</a></h3><p>A character who wishes to change alignment may do so between sessions. They inform the GM of the new alignment, and it takes effect immediately. For most characters, there are no mechanical consequences. For Paladins, Clerics, and Druids, the new alignment is checked against class requirements. If it falls outside the permitted range, class abilities are suspended until atonement or the alignment is reversed.</p><h3 id="involuntary-drift" tabindex="-1"><strong>Involuntary Drift</strong> <a class="header-anchor" href="#involuntary-drift" aria-label="Permalink to &quot;**Involuntary Drift**&quot;">​</a></h3><p>If a character&#39;s established behavior has drifted outside their stated alignment without a conscious choice being made, the GM may declare the alignment changed. This is not a penalty, but recognition of what the character has already become. Class ability suspension applies if applicable.</p><h3 id="atonement" tabindex="-1"><strong>Atonement</strong> <a class="header-anchor" href="#atonement" aria-label="Permalink to &quot;**Atonement**&quot;">​</a></h3><p>A character who has lost class abilities through alignment violation can recover them through atonement — a specific act or sequence of acts determined by the GM in light of the nature and severity of the violation. For Paladins, this typically involves their deity&#39;s clergy directly. For Clerics, the same. For Druids, it involves the Hyerophancy. Atonement is always earned through action, not through declaration.</p><hr><h2 id="alignment-and-reaction" tabindex="-1"><strong>Alignment and Reaction</strong> <a class="header-anchor" href="#alignment-and-reaction" aria-label="Permalink to &quot;**Alignment and Reaction**&quot;">​</a></h2><p>Alignment affects reaction rolls in specific circumstances. Characters of strongly opposed alignments — Lawful Good and Chaotic Evil, for example — begin encounters with NPCs of the opposing alignment at one step worse on the reaction table, before other modifiers are applied. The GM adjudicates whether the NPC is sufficiently aware of the character&#39;s alignment for this to apply. Alignment is not written on a person&#39;s face. It emerges through behavior.</p><hr><h3 id="table-5-1-alignment-quick-reference" tabindex="-1"><strong>Table 5.1: Alignment Quick Reference</strong> <a class="header-anchor" href="#table-5-1-alignment-quick-reference" aria-label="Permalink to &quot;**Table 5.1: Alignment Quick Reference**&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>Lawful</th><th>Neutral</th><th>Chaotic</th></tr></thead><tbody><tr><td><strong>Good</strong></td><td>Lawful Good</td><td>Neutral Good</td><td>Chaotic Good</td></tr><tr><td><strong>Neutral</strong></td><td>Lawful Neutral</td><td>True Neutral</td><td>Chaotic Neutral</td></tr><tr><td><strong>Evil</strong></td><td>Lawful Evil</td><td>Neutral Evil</td><td>Chaotic Evil</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Alignment</th><th>Core Orientation</th></tr></thead><tbody><tr><td>Lawful Good</td><td>Order and genuine concern for others. Breaks unjust laws openly.</td></tr><tr><td>Neutral Good</td><td>Good outcomes through whatever means work. No position on order.</td></tr><tr><td>Chaotic Good</td><td>Genuine concern for others, contempt for institutional authority.</td></tr><tr><td>Lawful Neutral</td><td>Structure and obligation. The contract matters. Outside it, indifferent.</td></tr><tr><td>True Neutral</td><td>No consistent position. Local loyalties, case-by-case judgment.</td></tr><tr><td>Chaotic Neutral</td><td>Personal freedom and self-direction. Not malicious, not reliable.</td></tr><tr><td>Lawful Evil</td><td>Self-interest within a code, used as a tool for cover and coordination.</td></tr><tr><td>Neutral Evil</td><td>Self-interest, no preference for order or freedom, no limiting principles.</td></tr><tr><td>Chaotic Evil</td><td>Self-interest with contempt for all constraint.</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Class</th><th>Alignment Requirement</th></tr></thead><tbody><tr><td>Paladin</td><td>Lawful (specific alignment per deity)</td></tr><tr><td>Cleric</td><td>Within one step of deity&#39;s alignment</td></tr><tr><td>Druid</td><td>Neutral on at least one axis</td></tr><tr><td>Champion</td><td>None (Code operates independently)</td></tr><tr><td>All others</td><td>None</td></tr></tbody></table>',50)])])}const m=t(i,[["render",r]]);export{g as __pageData,m as default};
